import{_ as t,o,c as a,ag as i}from"./chunks/framework.BYYsWsaA.js";const p=JSON.parse('{"title":"Collaboration & Sharing","description":"","frontmatter":{},"headers":[],"relativePath":"guide/collaboration.md","filePath":"guide/collaboration.md"}'),r={name:"guide/collaboration.md"};function s(n,e,l,d,h,c){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="collaboration-sharing" tabindex="-1">Collaboration &amp; Sharing <a class="header-anchor" href="#collaboration-sharing" aria-label="Permalink to &quot;Collaboration &amp; Sharing&quot;">​</a></h1><p>Wafflebase lets multiple people edit the same sheet or document at the same time. Share via link — no account required for recipients.</p><h2 id="share-a-document" tabindex="-1">Share a Document <a class="header-anchor" href="#share-a-document" aria-label="Permalink to &quot;Share a Document&quot;">​</a></h2><ol><li>Open the sheet or document you want to share</li><li>Click the <strong>Share</strong> button in the toolbar</li><li>Choose the access level: <ul><li><strong>View</strong> — Can see the content, but not edit</li><li><strong>Edit</strong> — Full editing access</li></ul></li><li>Optionally set an expiration (1 hour, 8 hours, 24 hours, or 7 days)</li><li>Click <strong>Create Link</strong> and copy the URL</li></ol><p>Send the link to anyone. They can open it in their browser without signing in.</p><h2 id="access-levels" tabindex="-1">Access Levels <a class="header-anchor" href="#access-levels" aria-label="Permalink to &quot;Access Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Permission</th><th>Viewer</th><th>Editor</th></tr></thead><tbody><tr><td>View content</td><td>Yes</td><td>Yes</td></tr><tr><td>Navigate and scroll</td><td>Yes</td><td>Yes</td></tr><tr><td>Select and copy</td><td>Yes</td><td>Yes</td></tr><tr><td>Edit content</td><td>No</td><td>Yes</td></tr><tr><td>Format (cells or text)</td><td>No</td><td>Yes</td></tr><tr><td>Undo/redo</td><td>No</td><td>Yes</td></tr></tbody></table><p>In sheets, editors can also use formulas, insert/delete rows and columns, and resize columns. In docs, editors can apply text formatting and paragraph alignment.</p><h2 id="edit-together" tabindex="-1">Edit Together <a class="header-anchor" href="#edit-together" aria-label="Permalink to &quot;Edit Together&quot;">​</a></h2><p>When a collaborator opens your shared link, you&#39;ll see:</p><ul><li><strong>Their cursor</strong> — In sheets, a colored highlight on their selected cell. In docs, a colored text cursor at their position.</li><li><strong>Their name</strong> — Appears near their cursor so you know who&#39;s editing where</li><li><strong>Live changes</strong> — Edits appear instantly with no need to refresh or save</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Each collaborator gets a unique color. If your collaborators sign in with GitHub, their name will appear next to their cursor.</p></div><h2 id="how-conflicts-work" tabindex="-1">How Conflicts Work <a class="header-anchor" href="#how-conflicts-work" aria-label="Permalink to &quot;How Conflicts Work&quot;">​</a></h2><p>What happens if two people edit the same cell or text at the same time?</p><p>Wafflebase uses CRDTs (Conflict-free Replicated Data Types) to handle this. Both edits are preserved in the system — the last writer&#39;s value is displayed in sheets, and concurrent text insertions are merged in docs. There&#39;s no &quot;conflict dialog&quot; or manual merge step.</p><p>In practice, presence cursors make it easy to see where others are working, so simultaneous edits to the same location are rare.</p><h2 id="manage-share-links" tabindex="-1">Manage Share Links <a class="header-anchor" href="#manage-share-links" aria-label="Permalink to &quot;Manage Share Links&quot;">​</a></h2><p>To see or revoke existing links:</p><ol><li>Open the sheet or document</li><li>Click <strong>Share</strong> in the toolbar</li><li>You&#39;ll see a list of active links with their role and expiration</li><li>Click the delete icon next to a link to revoke it immediately</li></ol><p>Revoking a link immediately blocks access — anyone with that URL will no longer be able to open it.</p><h2 id="good-to-know" tabindex="-1">Good to Know <a class="header-anchor" href="#good-to-know" aria-label="Permalink to &quot;Good to Know&quot;">​</a></h2><ul><li>Revoking or expiring a link blocks access immediately</li><li>Deleting a document automatically invalidates all its share links</li><li>Links cannot be guessed — each one is generated with a unique random ID</li><li>For sensitive data, use short expirations (1 hour or 8 hours)</li></ul><h2 id="tips-for-collaboration" tabindex="-1">Tips for Collaboration <a class="header-anchor" href="#tips-for-collaboration" aria-label="Permalink to &quot;Tips for Collaboration&quot;">​</a></h2><ul><li><strong>Use clear names</strong> — Title your sheets and documents descriptively so teammates can find them</li><li><strong>Communicate changes</strong> — If you restructure columns or reorganize content, let your team know</li><li><strong>Use separate tabs</strong> (sheets) — Give each team member their own tab for data entry, with a summary tab that pulls data using formulas</li></ul>',24)])])}const m=t(r,[["render",s]]);export{p as __pageData,m as default};
